INSERT INTO public.faqs (id, question, answer, category, order_index)
VALUES
('00000000-0000-0000-0009-000000000001', 'Can foreigners buy property in Dubai?', 'Yes. Foreigners and expats can buy property in designated freehold areas in Dubai. Freehold ownership gives you absolute ownership of the property and land, registered with the Dubai Land Department (DLD).', 'Buying Property', 1),
('00000000-0000-0000-0009-000000000002', 'What is the difference between freehold and leasehold properties?', 'Freehold properties give the buyer complete ownership of both the property unit and the land it sits on indefinitely. Leasehold properties, on the other hand, grant ownership rights for a fixed period (typically 30 to 99 years) while the land ownership remains with the freeholder.', 'Buying Property', 2),
('00000000-0000-0000-0009-000000000003', 'What are the transaction fees when purchasing a property in Dubai?', 'The typical fees include: DLD fee (4% of property price + 580 AED admin fee), Registration trustee fee (2,000 to 4,000 AED + VAT), Agency commission (typically 2% + VAT), and Mortgage registration fee (0.25% of loan value if applicable).', 'Buying Property', 3),
('00000000-0000-0000-0009-000000000004', 'Do I need a local bank account to buy real estate in Dubai?', 'No, a local bank account is not required. You can pay via international wire transfer, foreign currency drafts, or cryptocurrency (via licensed escrow agencies). However, having a local account makes ongoing payments and rent collections easier.', 'Buying Property', 4),
('00000000-0000-0000-0009-000000000005', 'What is the Ejari system in Dubai?', 'Ejari is the government-mandated registration system for rental agreements in Dubai. It secures the contract between landlord and tenant, makes it legally binding, and is required to connect water, electricity (DEWA), and internet services.', 'Renting', 1),
('00000000-0000-0000-0009-000000000006', 'Can a landlord evict a tenant in Dubai?', 'A landlord can evict a tenant only under specific conditions defined by Law No. 26 of 2007, such as non-payment of rent, sub-letting without consent, or if the landlord wishes to use the property for personal use. Eviction notices require 12 months'' notification sent via notary public.', 'Renting', 2),
('00000000-0000-0000-0009-000000000007', 'What is the Rent Calculator by RERA?', 'The Real Estate Regulatory Agency (RERA) Rent Calculator is an online index tool that governs maximum rental increase percentages allowed in Dubai based on average market rents in specific areas. Landlords must use it to calculate valid rent increases.', 'Renting', 3),
('00000000-0000-0000-0009-000000000008', 'How are rental payments typically structured in Dubai?', 'Rents are traditionally paid using post-dated cheques. The annual rent is split into 1, 2, 4, or sometimes 6 cheques. However, many developers and private landlords are starting to accept monthly direct debit or credit card payments.', 'Renting', 4),
('00000000-0000-0000-0009-000000000009', 'What is an Escrow Account in off-plan real estate?', 'Under Dubai Law, developers selling off-plan units must deposit all buyer payments into a project-specific Escrow Account approved by the DLD. Funds are released to the developer only as construction milestones are verified by independent engineers.', 'Off Plan', 1),
('00000000-0000-0000-0009-00000000000a', 'What happens if an off-plan project is delayed or cancelled?', 'The DLD and Real Estate Court protect buyers in case of developer default. If a project is cancelled, DLD liquidates the escrow account to refund investors. If delayed beyond contract thresholds, buyers can seek cancellation or compensation.', 'Off Plan', 2),
('00000000-0000-0000-0009-00000000000b', 'Can I sell my off-plan property before construction completion?', 'Yes, you can sell off-plan properties. Most developers require the buyer to have paid a minimum threshold (usually 30% to 40% of the total purchase price) before issuing a No Objection Certificate (NOC) for resale.', 'Off Plan', 3),
('00000000-0000-0000-0009-00000000000c', 'What does Oqood mean?', 'Oqood is a centralized online registration portal for off-plan properties in Dubai. It is issued by the DLD as an interim registration certificate to secure buyer rights during the construction phase until the final Title Deed is issued.', 'Off Plan', 4),
('00000000-0000-0000-0009-00000000000d', 'Can non-residents apply for a home loan in Dubai?', 'Yes, non-residents can obtain home mortgages from international and local banks operating in the UAE. The maximum Loan-to-Value (LTV) ratio for non-residents is usually 50% to 60%, whereas residents can get up to 80% LTV.', 'Mortgage', 1),
('00000000-0000-0000-0009-00000000000e', 'What is the maximum loan tenure in the UAE?', 'The maximum tenure for home mortgages in the UAE is 25 years. The borrower''s age at the time of final repayment must not exceed 65 years for salaried individuals, or 70 years for self-employed individuals.', 'Mortgage', 2),
('00000000-0000-0000-0009-00000000000f', 'What interest rate types are available?', 'Banks offer both fixed-rate mortgages (typically fixed for 1 to 5 years, converting to EIBOR + margin) and variable-rate mortgages linked directly to the 3-month or 6-month Emirates Interbank Offered Rate (EIBOR).', 'Mortgage', 3),
('00000000-0000-0000-0009-000000000010', 'Do banks require life insurance for UAE mortgages?', 'Yes. Almost all UAE banks require home buyers to take out a matching life insurance policy (which names the bank as beneficiary) and a home property insurance policy to protect the asset.', 'Mortgage', 4),
('00000000-0000-0000-0009-000000000011', 'How do I qualify for the 10-year UAE Golden Visa through real estate?', 'You qualify by purchasing one or more properties in freehold areas with a combined value of at least 2 million AED ($544,500 USD). The property can be ready or off-plan, mortgaged or paid in full.', 'Golden Visa', 1),
('00000000-0000-0000-0009-000000000012', 'Can off-plan properties qualify for the Golden Visa?', 'Yes. DLD allows buyers of off-plan properties to apply for the Golden Visa if they have paid at least 2 million AED to the developer, supported by Oqood interim certificates and payment receipts.', 'Golden Visa', 2),
('00000000-0000-0000-0009-000000000013', 'Can I sponsor my family with a Golden Visa?', 'Yes. Golden Visa holders can sponsor their spouses, children (including self-sponsored unmarried daughters and sons of any age), and domestic helper staff under their visa scheme.', 'Golden Visa', 3),
('00000000-0000-0000-0009-000000000014', 'Does the Golden Visa allow me to live outside the UAE?', 'Yes. Unlike normal residency visas which expire if you stay outside the UAE for more than 6 months, Golden Visa holders can stay outside the country for any duration without losing their residency status.', 'Golden Visa', 4),
('00000000-0000-0000-0009-000000000015', 'Why is Dubai considered a tax haven for property investors?', 'Dubai charges 0% personal income tax, 0% capital gains tax, and 0% property tax. The only taxes are a flat 5% corporate tax on businesses if applicable, and a 4% one-time registration fee on purchase.', 'Foreign Investment', 1),
('00000000-0000-0000-0009-000000000016', 'What is the average ROI on rental properties in Dubai?', 'Net rental yields in Dubai are among the highest globally, averaging between 5% and 8% per annum. Micro-apartments and holiday homes in prime areas (Downtown, Marina) can reach up to 10% gross yields.', 'Foreign Investment', 2),
('00000000-0000-0000-0009-000000000017', 'Can I invest in property using cryptocurrency?', 'Yes, many developers and real estate brokerages accept payments in Bitcoin (BTC), Ethereum (ETH), and USDT. Transactions are processed securely via regulated payment gateways that exchange crypto to AED cash.', 'Foreign Investment', 3),
('00000000-0000-0000-0009-000000000018', 'Are foreign currency funds repatriable?', 'Yes. The UAE has no currency control regulations. 100% of capital, dividends, rental income, and profits can be fully repatriated back to your home country in any currency.', 'Foreign Investment', 4),
('00000000-0000-0000-0009-000000000019', 'What is a Title Deed in Dubai?', 'A Title Deed is the final legal document issued by the DLD that registers you as the absolute owner of the property. It contains unique parcel IDs, floor size, ownership details, and property borders.', 'Property Registration', 1),
('00000000-0000-0000-0009-00000000001a', 'What is a Power of Attorney (POA)?', 'A Power of Attorney allows you to appoint a trusted representative or broker to manage purchase transactions, sign contracts, and handle key transfers on your behalf without you needing to be physically present in the UAE.', 'Property Registration', 2),
('00000000-0000-0000-0009-00000000001b', 'How long does the property transfer process take?', 'A standard resale property transaction takes between 2 to 4 weeks from signing the Memorandum of Understanding (MOU/Form F) to the final transfer meeting at the DLD Trustee office.', 'Property Registration', 3),
('00000000-0000-0000-0009-00000000001c', 'What is a No Objection Certificate (NOC)?', 'An NOC is a certificate issued by the master developer (e.g. Emaar, DAMAC) confirming that the seller has settled all service charges and utility bills, clearing the property for resale and transfer.', 'Property Registration', 4),
('00000000-0000-0000-0009-00000000001d', 'Who are the top developers in Dubai?', 'The largest state-backed and private developers include Emaar Properties, DAMAC Properties, Nakheel, Sobha Realty, Meraas, Omniyat, and Ellington. They manage the master developments of most areas.', 'Developer Questions', 1),
('00000000-0000-0000-0009-00000000001e', 'What is a master community?', 'A master community is a master-planned neighborhood (like Downtown Dubai or Dubai Hills Estate) built, managed, and serviced by a single master developer, ensuring uniform architecture, roads, parks, and security.', 'Developer Questions', 2),
('00000000-0000-0000-0009-00000000001f', 'Do developers provide post-handover payment plans?', 'Yes, many developers offer post-handover payment plans (PHPP) ranging from 2 to 5 years after completion. This allows you to pay for the property using rental income after moving in.', 'Developer Questions', 3),
('00000000-0000-0000-0009-000000000020', 'What are service charges?', 'Service charges are monthly or annual maintenance fees paid to the owners'' association or master developer. They cover building upkeep, common areas, security, swimming pool, and gym maintenance.', 'Developer Questions', 4),
('00000000-0000-0000-0009-000000000021', 'What services do property management companies offer?', 'Property managers handle tenant sourcing, Ejari setup, rent collections, maintenance repairs, and disputes with the rental committee, allowing overseas owners to run a completely hands-off investment.', 'Property Management', 1),
('00000000-0000-0000-0009-000000000022', 'Can I convert my property into a short-term holiday home?', 'Yes. You can register your apartment as a holiday home with the Department of Economy and Tourism (DET). Short-term holiday lets typically yield 20% to 35% higher income than long-term rents.', 'Property Management', 2),
('00000000-0000-0000-0009-000000000023', 'Who pays for property repairs in a rental?', 'Generally, minor maintenance (under 500 AED) is paid by the tenant, while major structural maintenance (AC compressors, plumbing leaks, electrical faults) is paid by the landlord, unless agreed otherwise.', 'Property Management', 3),
('00000000-0000-0000-0009-000000000024', 'What is the tenant security deposit rate in Dubai?', 'The standard security deposit is 5% of the annual rent for unfurnished properties, and 10% for fully furnished properties. It is held by the landlord and returned to the tenant upon lease completion.', 'Property Management', 4),
('00000000-0000-0000-0009-000000000025', 'Is there VAT on residential properties in the UAE?', 'No. First-time buyers of residential properties within the first 3 years of completion are zero-rated. Commercial real estate transactions, however, attract a 5% Value Added Tax (VAT).', 'Tax & Payments', 1),
('00000000-0000-0000-0009-000000000026', 'What is corporate tax on rental income?', 'Rental income earned by private individuals directly from real estate investments in their personal capacity is exempted from the UAE''s 9% corporate tax that took effect in 2023.', 'Tax & Payments', 2),
('00000000-0000-0000-0009-000000000027', 'How do currency exchange fluctuations affect UAE investments?', 'The UAE Dirham (AED) is pegged to the US Dollar (USD) at a fixed rate of 3.6725. This removes exchange risk for international investors holding assets in USD or pegged currencies.', 'Tax & Payments', 3),
('00000000-0000-0000-0009-000000000028', 'What is service charge indexation?', 'The DLD runs a Service Charge Index that caps and regulates the amount developers can charge per square foot for maintenance, ensuring transparency and preventing arbitrary rate hikes.', 'Tax & Payments', 4)
